import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { useState } from "react";
import classes from "./app.module.css";
import Home from "../components/pages/Home";
import Login from "../components/pages/Login";
import CalorieCalc from "../components/pages/CalorieCalc";
import Profile from "../components/pages/Profile";
import NavBar from "../components/navBar/NavBar";
import NotFound from "../components/pages/NotFound";

// Define pages configuration
const pages = [
  { name: "Login", path: "/" },
  { name: "Home", path: "/home" },
  { name: "מחשבון קלוריות", path: "/CalorieCalc" },
  { name: "תפריט", path: "/menu" },
  { name: "אודות", path: "/about" },
  { name: "צור קשר", path: "/contact" },
  { name: "Profile", path: "/profile" },
];

// Authentication guard component
const RequireAuth = ({ children, allowGuest = false }) => {
  const location = useLocation();
  const isLoggedIn = false; // This would normally come from auth state

  // Allow guest access to home page
  if (!isLoggedIn && !allowGuest) {
    return <Navigate to="/" state={{ from: location }} replace />;
  }

  return children;
};

export default function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  // Authentication handlers
  const handleLogin = (user) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
  };

  return (
    <section className={classes.app}>
      <BrowserRouter>
        <Routes>
          <Route path="/" element={<Login onLoginSuccess={handleLogin} />} />
          <Route
            path="/home"
            element={
              <RequireAuth allowGuest>
                <>
                  <NavBar
                    pages={pages}
                    isLoggedIn={isLoggedIn}
                    onLogout={handleLogout}
                    currentUser={currentUser}
                  />
                  <Home />
                </>
              </RequireAuth>
            }
          />
          <Route
            path="/CalorieCalc"
            element={
              <RequireAuth>
                <>
                  <NavBar
                    pages={pages}
                    isLoggedIn={isLoggedIn}
                    onLogout={handleLogout}
                    currentUser={currentUser}
                  />
                  <CalorieCalc />
                </>
              </RequireAuth>
            }
          />
          <Route
            path="/profile"
            element={
              <RequireAuth>
                <>
                  <NavBar
                    pages={pages}
                    isLoggedIn={isLoggedIn}
                    onLogout={handleLogout}
                    currentUser={currentUser}
                  />
                  <Profile />
                </>
              </RequireAuth>
            }
          />
          <Route path="*" element={<NotFound />} />
        </Routes>
      </BrowserRouter>
    </section>
  );
}
